const base = 'https://services.leadconnectorhq.com';
const H = { Authorization: 'Bearer ' + inputData.pit, Version: '2021-04-15', Accept: 'application/json' };
const out = {};
try {
  const cals = String(inputData.calendarIds).split(',');
  const r = await customRequest.get(base + '/contacts/' + inputData.contactId + '/appointments', { headers: H });
  const body = (r && r.data) ? r.data : r;
  const events = (body && body.events) || [];
  const cands = events
    .filter((e) => cals.indexOf(String(e.calendarId)) > -1 && e.appointmentStatus !== 'cancelled')
    .sort((a, b) => new Date(String(a.startTime).replace(' ', 'T')) - new Date(String(b.startTime).replace(' ', 'T')));
  const target = cands[cands.length - 1]; // latest start time — matches GHL's own 'most recent' rule
  out.candidates = String(cands.length);
  out.targetId = target ? target.id : 'none';
  if (target && target.appointmentStatus !== 'confirmed') {
    // customRequest.put takes (url, { headers, data }) — NOT axios (url, data, config)
    await customRequest.put(base + '/calendars/events/appointments/' + target.id,
      { headers: H, data: { appointmentStatus: 'confirmed', toNotify: false } });
    out.confirmed = 'yes';
  } else {
    out.confirmed = target ? 'already' : 'no-target';
  }
} catch (e) {
  out.err = String((e && e.message) || JSON.stringify(e)).slice(0, 200);
}
return out;
